'use server';

import { updateTag } from 'next/cache';

import { createPost, POSTS_TAG } from './posts';

export async function createPostAction(formData: FormData) {
  const title = String(formData.get('title') ?? '').trim();
  const body = String(formData.get('body') ?? '').trim();

  if (!title || !body) {
    throw new Error('Title and body are required.');
  }

  createPost(title, body);

  // updateTag expires the tagged cache immediately, so the next read cannot
  // serve stale data while waiting for background revalidation.
  updateTag(POSTS_TAG);
}
import { unstable_cache } from 'next/cache';

export const POSTS_TAG = 'posts';

export type Post = {
  id: number;
  title: string;
  body: string;
};

const posts: Post[] = [];

export function createPost(title: string, body: string): Post {
  const post = {
    id: Date.now(),
    title,
    body
  };

  posts.unshift(post);
  return post;
}

async function readPosts(): Promise<Post[]> {
  return posts;
}

export const getPosts = unstable_cache(readPosts, ['posts-list'], {
  tags: [POSTS_TAG]
});
import { createPostAction } from './actions';
import { getPosts } from './posts';

export const dynamic = 'force-dynamic';

export default async function Home() {
  const posts = await getPosts();

  return (
    <main style={{ maxWidth: 720, margin: '0 auto', padding: 24 }}>
      <h1>Posts</h1>
      <form action={createPostAction} style={{ display: 'grid', gap: 8, marginBottom: 32 }}>
        <label htmlFor="title">Title</label>
        <input id="title" name="title" required />
        <label htmlFor="body">Body</label>
        <textarea id="body" name="body" required rows={4} />
        <button type="submit">Create post</button>
      </form>

      <section aria-label="Posts">
        {posts.length === 0 ? <p>No posts yet.</p> : null}
        {posts.map((post) => (
          <article key={post.id}>
            <h2>{post.title}</h2>
            <p>{post.body}</p>
          </article>
        ))}
      </section>
    </main>
  );
}
